<?php
/**
 * AJAX: Get Library Book Issues
 * 
 * @author School ERP Development Team
 * @version 1.0.0
 */

// Start output buffering FIRST to catch any unwanted output
ob_start();

require_once '../../config/config.php';

// NOW suppress error display AFTER config is loaded
error_reporting(E_ALL);
ini_set('display_errors', 0);
ini_set('display_startup_errors', 0);

// Clear any output that might have been generated by config.php
ob_clean();

// Set JSON header early
header('Content-Type: application/json; charset=utf-8');
header('Cache-Control: no-cache, must-revalidate');

// Support both session-based (web) and user_id parameter (Flutter/mobile) authentication
$currentUser = null;
$userId = $_GET['user_id'] ?? $_POST['user_id'] ?? null;

if ($userId) {
    // Flutter/mobile app authentication
    $sql = "SELECT u.*, r.role_name, b.branch_name 
            FROM users u 
            LEFT JOIN roles r ON u.role_id = r.id 
            LEFT JOIN branches b ON u.branch_id = b.id 
            WHERE u.id = ? AND u.is_active = 1";
    $stmt = executeQuery($sql, 'i', [$userId]);
    $currentUser = fetchOne($stmt);
    
    if (!$currentUser) {
        jsonResponse(false, 'Invalid user ID');
    }
} else {
    // Web session-based authentication
    if (!isLoggedIn()) {
        jsonResponse(false, 'Unauthorized');
    }
    $currentUser = getCurrentUser();
}

$bookId = $_GET['book_id'] ?? null;
$memberId = $_GET['member_id'] ?? null;
$status = $_GET['status'] ?? null;

try {
    $sql = "SELECT li.*, 
            b.book_title, b.isbn as book_isbn,
            s.first_name, s.last_name, s.student_id as admission_no,
            u1.username as issued_by_name, u2.username as returned_by_name
            FROM library_issues li
            INNER JOIN library_books b ON li.book_id = b.id
            INNER JOIN students s ON li.student_id = s.id
            LEFT JOIN users u1 ON li.issued_by = u1.id
            LEFT JOIN users u2 ON li.returned_to = u2.id
            WHERE 1=1";
    
    $params = [];
    $types = '';
    
    if ($bookId) {
        $sql .= " AND li.book_id = ?";
        $params[] = $bookId;
        $types .= 'i';
    }
    
    if ($memberId) {
        $sql .= " AND li.student_id = ?";
        $params[] = $memberId;
        $types .= 'i';
    }
    
    if ($status) {
        $sql .= " AND li.status = ?";
        $params[] = $status;
        $types .= 's';
    }
    
    // Check for overdue
    if ($status == 'Issued') {
        $sql .= " AND li.due_date < CURDATE() AND li.status = 'Issued'";
    }
    
    $sql .= " ORDER BY li.issue_date DESC, li.created_at DESC";
    
    $stmt = !empty($params) ? executeQuery($sql, $types, $params) : executeQuery($sql);
    $issues = fetchAll($stmt);
    
    // Format the data
    $formatted = [];
    foreach ($issues as $issue) {
        // Check if overdue
        $isOverdue = false;
        if ($issue['due_date'] && $issue['status'] == 'Issued') {
            $dueDate = new DateTime($issue['due_date']);
            $isOverdue = $dueDate < new DateTime();
        }
        
        $formatted[] = [
            'id' => $issue['id'],
            'book_id' => $issue['book_id'],
            'book_title' => $issue['book_title'],
            'book_isbn' => $issue['book_isbn'],
            'member_id' => $issue['student_id'],
            'member_name' => trim($issue['first_name'] . ' ' . $issue['last_name']),
            'member_type' => 'Student',
            'member_id_number' => $issue['admission_no'],
            'issue_date' => $issue['issue_date'],
            'due_date' => $issue['due_date'],
            'return_date' => $issue['return_date'],
            'status' => $isOverdue ? 'Overdue' : $issue['status'],
            'fine_amount' => $issue['fine_amount'] ?? 0,
            'remarks' => $issue['remarks'],
            'issued_by' => $issue['issued_by'],
            'issued_by_name' => $issue['issued_by_name'],
            'returned_by' => $issue['returned_to'],
            'returned_by_name' => $issue['returned_by_name'],
            'created_at' => $issue['created_at'],
        ];
    }
    
    jsonResponse(true, 'Issues loaded', $formatted);
    
} catch (Exception $e) {
    jsonResponse(false, 'Failed to load issues: ' . $e->getMessage());
}

